```class Solution {
public:
    int numberOfWays(int n, int x, int y) {
        int result = 1;
        for (int i = 1; i <= x; i++) {
            result = (result * (n / i)) % 1000000007;
        }
        result = (result * (y)) % 1000000007;
        return result;
    }
};
```

